export function sineWave({ periods = 1, samplesPerPeriod = 100, amplitude = 1, phase = 0, noise = 0, seed = 1, startTime = 0, timeStep = null } = {}) {
  const total = Math.max(1, Math.floor(periods * samplesPerPeriod));
  const dt = timeStep != null ? timeStep : 1 / samplesPerPeriod;
  const rand = mulberry32(seed || 1);
  const gauss = seededNormal(rand);
  const out = new Array(total);
  for (let i = 0; i < total; i++) {
    const t = startTime + i * dt;
    const angle = 2 * Math.PI * periods * (i / total) + phase;
    let v = amplitude * Math.sin(angle);
    if (noise && noise > 0) {
      v += gauss() * noise;
    }
    out[i] = { time: t, value: v };
  }
  return out;
}

export function randomWalk({ seed = 1, steps = 100, startValue = 0, stepMean = 0, stepStd = 1, startTime = 0, timeStep = 1 } = {}) {
  const rand = mulberry32(seed >>> 0);
  const gauss = seededNormal(rand);
  const out = new Array(steps);
  let value = startValue;
  for (let i = 0; i < steps; i++) {
    const t = startTime + i * timeStep;
    const step = stepMean + gauss() * stepStd;
    value += step;
    out[i] = { time: t, value };
  }
  return out;
}

export function parseCSV(text) {
  if (typeof text !== "string") throw new TypeError("CSV input must be a string");
  const lines = text.split(/\r?\n/).map((l) => l.trim()).filter(Boolean);
  const out = [];
  if (lines.length === 0) return out;
  let startLine = 0;
  // Detect header
  const header = lines[0].split(/,|;|\t/).map(h => h.trim().toLowerCase());
  if (header.length >= 2 && header[0].includes('time') && header[1].includes('value')) {
    startLine = 1;
  }
  for (let i = startLine; i < lines.length; i++) {
    const parts = lines[i].split(/,|;|\t/).map(p => p.trim());
    if (parts.length < 2) continue;
    const rawTime = parts[0];
    const rawVal = parts[1];
    let timeVal = Number(rawTime);
    let time;
    if (!Number.isFinite(timeVal)) {
      // Try ISO 8601
      const parsed = Date.parse(rawTime);
      if (!Number.isNaN(parsed)) {
        time = parsed / 1000; // seconds
      } else {
        // fallback: use index
        time = i - startLine;
      }
    } else {
      // numeric: decide seconds or milliseconds
      // If very large (>= 1e12) treat as ms
      if (Math.abs(timeVal) > 1e12) {
        time = timeVal / 1000;
      } else if (Math.abs(timeVal) > 1e9) {
        // likely milliseconds
        time = timeVal / 1000;
      } else {
        time = timeVal; // seconds
      }
    }
    const value = Number(rawVal);
    if (!Number.isFinite(value)) continue;
    out.push({ time, value });
  }
  return out;
}

export function normalise(data, { interval = null, startTime = null, endTime = null } = {}) {
  if (!Array.isArray(data) || data.length === 0) return [];
  const sorted = [...data].slice().sort((a, b) => a.time - b.time);
  const times = sorted.map(d => d.time);
  const values = sorted.map(d => d.value);
  // determine interval by median diff if not provided
  if (interval == null) {
    const diffs = [];
    for (let i = 1; i < times.length; i++) diffs.push(times[i] - times[i - 1]);
    if (diffs.length === 0) interval = 1;
    else {
      const sortedDiffs = diffs.slice().sort((a, b) => a - b);
      interval = sortedDiffs[Math.floor(sortedDiffs.length / 2)];
      if (!isFinite(interval) || interval <= 0) interval = diffs[0];
    }
  }
  const start = startTime != null ? startTime : times[0];
  const end = endTime != null ? endTime : times[times.length - 1];
  if (end < start) return [];
  const n = Math.max(1, Math.floor((end - start) / interval));
  const out = [];
  for (let i = 0; i <= n; i++) {
    const t = start + i * interval;
    // find neighbors
    if (t <= times[0]) {
      out.push({ time: t, value: values[0] });
      continue;
    }
    if (t >= times[times.length - 1]) {
      out.push({ time: t, value: values[values.length - 1] });
      continue;
    }
    // binary search for right index
    let lo = 0, hi = times.length - 1;
    while (lo <= hi) {
      const mid = Math.floor((lo + hi) / 2);
      if (times[mid] === t) { lo = mid; hi = mid; break; }
      if (times[mid] < t) lo = mid + 1; else hi = mid - 1;
    }
    const r = Math.min(times.length - 1, lo);
    const l = Math.max(0, r - 1);
    const tL = times[l], tR = times[r];
    const vL = values[l], vR = values[r];
    let v;
    if (tR === tL) v = vL; else {
      const frac = (t - tL) / (tR - tL);
      v = vL + frac * (vR - vL);
    }
    out.push({ time: t, value: v });
  }
  return out;
}

export function movingAverageForecast(history, { window = 3, horizon = 1 } = {}) {
  if (!Array.isArray(history) || history.length === 0) return [];
  const vals = history.map(d => d.value);
  const times = history.map(d => d.time);
  const dt = times.length >= 2 ? (times[times.length - 1] - times[times.length - 2]) : 1;
  const series = vals.slice();
  const preds = [];
  for (let h = 0; h < horizon; h++) {
    const start = Math.max(0, series.length - window);
    const lastWindow = series.slice(start);
    const avg = lastWindow.reduce((s, x) => s + x, 0) / lastWindow.length;
    const nextTime = times[times.length - 1] + (h + 1) * dt;
    preds.push({ time: nextTime, value: avg });
    series.push(avg);
  }
  return preds;
}

export function exponentialSmoothingForecast(history, { alpha = 0.5, horizon = 1 } = {}) {
  if (!Array.isArray(history) || history.length === 0) return [];
  const vals = history.map(d => d.value);
  const times = history.map(d => d.time);
  const dt = times.length >= 2 ? (times[times.length - 1] - times[times.length - 2]) : 1;
  let s = vals[0];
  for (let i = 0; i < vals.length; i++) {
    s = alpha * vals[i] + (1 - alpha) * s;
  }
  const preds = [];
  for (let h = 0; h < horizon; h++) {
    preds.push({ time: times[times.length - 1] + (h + 1) * dt, value: s });
  }
  return preds;
}

export function crossCorrelation(seriesA, seriesB, { maxLag = 20, interval = null } = {}) {
  if (!Array.isArray(seriesA) || !Array.isArray(seriesB)) return [];
  // Resample both to a common uniform grid across their overlapping range
  const timesA = seriesA.map(d => d.time);
  const timesB = seriesB.map(d => d.time);
  const minA = Math.min(...timesA);
  const maxA = Math.max(...timesA);
  const minB = Math.min(...timesB);
  const maxB = Math.max(...timesB);
  const start = Math.max(minA, minB);
  const end = Math.min(maxA, maxB);
  if (end <= start) {
    // fallback: use union range
    const uStart = Math.min(minA, minB);
    const uEnd = Math.max(maxA, maxB);
    return crossCorrelation(seriesA, seriesB, { maxLag, interval: interval || 1, start, end: uEnd });
  }
  // Determine interval
  if (interval == null) {
    const diffs = [];
    for (let i = 1; i < timesA.length; i++) diffs.push(Math.abs(timesA[i] - timesA[i - 1]));
    for (let i = 1; i < timesB.length; i++) diffs.push(Math.abs(timesB[i] - timesB[i - 1]));
    if (diffs.length === 0) interval = 1; else {
      diffs.sort((a, b) => a - b);
      interval = diffs[Math.floor(diffs.length / 2)];
    }
  }
  const normA = normalise(seriesA, { interval, startTime: start, endTime: end });
  const normB = normalise(seriesB, { interval, startTime: start, endTime: end });
  const valuesA = normA.map(d => d.value);
  const valuesB = normB.map(d => d.value);
  const N = valuesA.length;
  const results = [];
  for (let lag = -maxLag; lag <= maxLag; lag++) {
    let x = [], y = [];
    if (lag >= 0) {
      const n = N - lag;
      if (n <= 0) { results.push({ lag, r: 0 }); continue; }
      x = valuesA.slice(0, n);
      y = valuesB.slice(lag, lag + n);
    } else {
      const n = N + lag; // lag is negative
      if (n <= 0) { results.push({ lag, r: 0 }); continue; }
      x = valuesA.slice(-lag, -lag + n);
      y = valuesB.slice(0, n);
    }
    const meanX = x.reduce((s, v) => s + v, 0) / x.length;
    const meanY = y.reduce((s, v) => s + v, 0) / y.length;
    let cov = 0, sx = 0, sy = 0;
    for (let i = 0; i < x.length; i++) {
      const dx = x[i] - meanX;
      const dy = y[i] - meanY;
      cov += dx * dy;
      sx += dx * dx;
      sy += dy * dy;
    }
    const denom = Math.sqrt(sx * sy);
    const r = denom === 0 ? 0 : cov / denom;
    results.push({ lag, r });
  }
  return results;
}

export function generateReport(datasets) {
  const many = Array.isArray(datasets) ? datasets : [{ name: 'data', data: datasets }];
  let md = '# Data Report\n\nGenerated by the time-series library.\n\n';
  md += '| Dataset | Rows | Min | Max | Mean | Trend |\n';
  md += '|---|---:|---:|---:|---:|---:|\n';
  for (const item of many) {
    const name = item.name || 'data';
    const data = item.data || [];
    const rows = data.length;
    const vals = data.map(d => d.value);
    const min = rows ? Math.min(...vals) : '';
    const max = rows ? Math.max(...vals) : '';
    const mean = rows ? (vals.reduce((s, v) => s + v, 0) / rows) : '';
    const slope = rows ? linearTrendSlope(data) : 0;
    const trend = slope > 0 ? `${slope.toFixed(6)} (up)` : slope < 0 ? `${slope.toFixed(6)} (down)` : 'flat';
    md += `| ${name} | ${rows} | ${min} | ${max} | ${mean} | ${trend} |\n`;
  }
  return md;
}
